---
## Scalar Version
```c
static inline NodeMask ntacle_diffuse(NodeMask m)
{
    NodeMask out = m;
    for(int n=0;n<162;n++)
    {
        if(m.w[n>>6] & (1ULL<<(n&63)))
        {
            NodeMask e = ntacle_edge_mask[n];
            out.w[0] |= e.w[0];
            out.w[1] |= e.w[1];
            out.w[2] |= e.w[2];
            out.w[3] |= e.w[3];
        }
    }
    return out;
}
```
