---
# Append Record
lock-free append
```c
static inline void wal_append(WALRecord* r)
{
    int lane = wal_lane_id();
    WALLane* L = &wal_lane[lane];
    uint32_t p = atomic_fetch_add(&L->pos,sizeof(WALRecord));
    memcpy(L->buffer+p,r,sizeof(WALRecord));
}
```
no lock
no contention
---
# WAL Flush Thread
dedicated thread
```c
void wal_flush_loop()
{
    while(1)
    {
        for(int i=0;i<WAL_STRIPES;i++)
        {
            WALLane* L=&wal_lane[i];
            uint32_t size = atomic_exchange(&L->pos,0);
            if(size==0) continue;
            write(wal_fd,L->buffer,size);
        }
        fdatasync(wal_fd);
    }
}
```
