} HydraTask;
```
---
# Task Queue
queue ต่อ head
```c
typedef struct
{
    _Atomic uint32_t head;
    _Atomic uint32_t tail;
    HydraTask tasks[TASK_QUEUE_SIZE];
} HydraQueue;
```
global
```c
static HydraQueue hydra_queue[HYDRA_HEADS];
```
---
# Push Task
enqueue
```c
static inline void hydra_push(int h, HydraTask* t)
{
    HydraQueue* q = &hydra_queue[h];
    uint32_t pos = atomic_fetch_add(&q->tail,1);
    q->tasks[pos % TASK_QUEUE_SIZE] = *t;
}
```
---
# Pop Task
```c
static inline int hydra_pop(int h, HydraTask* out)
{
    HydraQueue* q = &hydra_queue[h];
    uint32_t head = atomic_load(&q->head);
    uint32_t tail = atomic_load(&q->tail);
    if(head==tail)
        return 0;
    *out = q->tasks[head % TASK_QUEUE_SIZE];
    atomic_store(&q->head,head+1);
    return 1;
}
```
---
# Work Stealing
เมื่อ queue ว่าง
```c
static int hydra_steal(int h, HydraTask* out)
{
    for(int i=0;i<HYDRA_HEADS;i++)
    {
        if(i==h) continue;
        HydraQueue* q = &hydra_queue[i];
        uint32_t head = atomic_load(&q->head);
        uint32_t tail = atomic_load(&q->tail);
        if(tail-head > 1)
        {
            if(atomic_compare_exchange_strong(&q->head,&head,head+1))
            {
                *out = q->tasks[head % TASK_QUEUE_SIZE];
                return 1;
            }
        }
    }
    return 0;
}
```
---
# Hydra Worker Loop
thread หลัก
```c
void hydra_worker(int hid)
{
    HydraTask task;
    while(1)
    {
        if(hydra_pop(hid,&task))
        {
            hydra_execute(&task);
            continue;
        }
        if(hydra_steal(hid,&task))
        {
            hydra_execute(&task);
            continue;
        }
        cpu_relax();
    }
}
```
---
