    └── POGLS_HoneycombSlot        ← Reserved stub
```

**Context ทั้งหมดอยู่ใน struct เดียว, mmap เดียว, ไม่มี concept ของ "local authority"**

---

## 🎯 วิเคราะห์ Idea.txt (Hydra Head) กับโค้ดจริง

### สิ่งที่ต้องเพิ่มใน V3.1 มี 3 จุดหลัก:

---

### **จุดที่ 1: Spawning Condition — ปัญหาตอนนี้**

```c
// ปัจจุบัน POGLS_Context ไม่รู้จัก "High-Density Zone"
typedef struct {
    void*         mmap_base;    // mmap ทั้งไฟล์รวมกัน
    uint64_t      mmap_size;
    ...
    uint64_t      deep_count;   // รู้แค่จำนวน blocks รวม
} POGLS_Context;

// ❌ ไม่มี: zone tracking, density detection, threshold check
```

**ต้องเพิ่ม:**

```c
// ใน POGLS_Shadow (16B ยังมีที่ว่าง)
typedef struct __attribute__((packed)) POGLS_Shadow {
    int32_t  coord_scaled;
    uint32_t vector_flags;    // ← บิต 31 = is_high_density ได้เลย
    uint64_t deep_link;
} POGLS_Shadow;

// วิธีใช้ vector_flags บิตที่ยังไม่ใช้:
#define FLAG_HIGH_DENSITY   (1 << 31)   // trigger Hydra spawn
#define FLAG_HYDRA_OWNED    (1 << 30)   // block ถูก Hydra ดูแลอยู่
#define FLAG_DIRTY_ZONE     (1 << 29)   // รอ compaction
```

---

### **จุดที่ 2: Tethered Virtual Drive — โครงสร้างที่ต้องเพิ่ม**

```c
// ไฟล์ใหม่: pogls_hydra.h

#define HYDRA_MAGIC         "HYDR"
#define HYDRA_MAX_HEADS     16        // รองรับ 16 zones พร้อมกัน
#define HYDRA_SPAWN_THRESHOLD_MB  512 // zone หนักกว่า 512MB → spawn

typedef struct __attribute__((packed)) POGLS_HydraHead {
    char     magic[4];          /* "HYDR" identifier                  */
    uint8_t  head_id;           /* 0-15                               */
    uint8_t  status;            /* 0=idle 1=active 2=syncing 3=dead   */
    uint16_t reserved;

    /* Zone boundary — ชี้ไปยัง offset range ใน Main Core */
    uint64_t zone_offset_start;  /* byte offset ใน main mmap          */
    uint64_t zone_offset_end;

    /* Virtual Drive — mmap เฉพาะ zone นี้ */
    void*    local_mmap;         /* mmap ของ zone เฉพาะ              */
    uint64_t local_mmap_size;

    /* Local authority */
    uint32_t n_bits_local;       /* อาจต่างจาก Main (local scaling)  */
    uint32_t topo_level_local;
    uint64_t blocks_owned;       /* จำนวน blocks ที่ Hydra ดูแล      */

    /* Metrics สำหรับ Audit */
    uint64_t write_count;
    uint64_t compaction_count;
    double   last_latency_ms;
} POGLS_HydraHead;

typedef struct {
    POGLS_HydraHead  heads[HYDRA_MAX_HEADS];
    uint8_t          active_count;
    POGLS_Context*   main_core;    /* pointer กลับไป Main — read only */

    /* Spawn/Retract callbacks */
    int (*on_spawn)(POGLS_HydraHead*, POGLS_Context*);
    int (*on_retract)(POGLS_HydraHead*, POGLS_Context*);
} POGLS_HydraCore;
```

---

### **จุดที่ 3: Integration กับ AUDIT (Architect_redesign.txt)**

ใน Architect_redesign.txt พูดถึง Dynamic GC threshold — **ควรเชื่อมกับ Hydra** แบบนี้:

```c
// Audit observe → ส่งสัญญาณ → Hydra Core ตัดสินใจ
typedef struct {
    uint64_t  zone_offset;
    double    frame_variance_ms;
    double    memory_usage_delta;
    uint32_t  allocation_freq;
    double    queue_latency_ms;

    // Dynamic threshold ตาม Architect_redesign
    float     gc_threshold;     // คำนวณจาก zone_size ไม่ใช่ hardcode 30%
    uint8_t   spawn_recommended; // 1 = Audit แนะนำให้ spawn Hydra Head
} POGLS_AuditSignal;

// Audit ไม่ควบคุมตรง — ส่ง signal ให้ Hydra Core ตัดสินใจ
// (ตรงกับ spec ใน idea.txt: "Audit observes but never controls directly")
```

